using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------

var notebook = new ResearchNotebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(
        (string query) => WebSearchTool.SearchAsync(query),
        "web_search",
        "Searches the web for the given query and returns a list of result snippets with titles and URLs."),

    AIFunctionFactory.Create(
        ([Description("A concise heading for this note")] string title,
         [Description("The note content to save")] string content) =>
        {
            notebook.AddNote(title, content);
            return $"Note saved: \"{title}\"";
        },
        "save_note",
        "Saves a research note to the notebook for later use in the summary."),

    AIFunctionFactory.Create(
        () => notebook.GetAllNotes(),
        "get_notes",
        "Retrieves all previously saved research notes."),
};

// --- Agent setup -------------------------------------------------------------

IChatClient chatClient = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI research agent that searches the web and summarizes findings.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    });

// --- Run ---------------------------------------------------------------------

Console.WriteLine("Research Agent");
Console.WriteLine(new string('=', 60));
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return 1;
}

Console.WriteLine($"\nResearching: {topic}\n");

var instructions = $"""
    You are a research agent. Your goal is to thoroughly research the following topic
    and produce a well-structured summary.

    Topic: {topic}

    Follow these steps:
    1. Use the web_search tool to find relevant information. Perform 2-3 searches
       with different, complementary queries to get broad coverage.
    2. For each useful finding, use save_note to record the key facts with a
       descriptive title.
    3. Once you have gathered enough information, use get_notes to review everything,
       then produce a final summary.

    Your final response must be a structured summary with:
    - A brief overview
    - Key findings (bullet points)
    - Sources referenced
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.User, instructions),
};

var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync(messages, session);

Console.WriteLine("=== Research Summary ===\n");
Console.WriteLine(response.Message?.Text ?? "(No response generated)");
Console.WriteLine();

if (notebook.Notes.Count > 0)
{
    Console.WriteLine($"--- {notebook.Notes.Count} note(s) saved during research ---");
}

return 0;

// =============================================================================
// Supporting types
// =============================================================================

/// <summary>Simple in-memory notebook for the agent to store research notes.</summary>
sealed class ResearchNotebook
{
    public List<(string Title, string Content)> Notes { get; } = [];

    public void AddNote(string title, string content) =>
        Notes.Add((title, content));

    public string GetAllNotes() =>
        Notes.Count == 0
            ? "No notes saved yet."
            : string.Join("\n\n", Notes.Select((n, i) =>
                $"[{i + 1}] {n.Title}\n{n.Content}"));
}

/// <summary>Web search tool using DuckDuckGo Instant Answer API (no key required).</summary>
static class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
        Timeout = TimeSpan.FromSeconds(15),
    };

    public static async Task<string> SearchAsync(string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await s_http.GetFromJsonAsync<JsonElement>(url);

            var results = new List<string>();

            // Abstract / instant answer
            var abstractText = json.TryGetProperty("AbstractText", out var at) ? at.GetString() : null;
            var abstractSource = json.TryGetProperty("AbstractSource", out var asrc) ? asrc.GetString() : null;
            var abstractUrl = json.TryGetProperty("AbstractURL", out var au) ? au.GetString() : null;
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"Source: {abstractSource}\nURL: {abstractUrl}\n{abstractText}");
            }

            // Related topics
            if (json.TryGetProperty("RelatedTopics", out var topics) && topics.ValueKind == JsonValueKind.Array)
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var firstUrl = topic.TryGetProperty("FirstURL", out var fu) ? fu.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add($"URL: {firstUrl}\n{text}");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n---\n", results)
                : $"No detailed results found for \"{query}\". Try a different search query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

