2. using System.Net.Http.Json;
3. using System.Text.Json;
4. using Microsoft.Agents.AI;
5. using Microsoft.Extensions.AI;
6. 
7. // --- Configuration -----------------------------------------------------------
8. 
9. var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
10.     ?? throw new InvalidOperationException(
11.         "Set the OPENAI_API_KEY environment variable before running.");
12. 
13. var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";
14. 
15. // --- Tools -------------------------------------------------------------------
16. 
17. var notebook = new ResearchNotebook();
18. 
19. var tools = new AITool[]
20. {
21.     AIFunctionFactory.Create(
22.         (string query) => WebSearchTool.SearchAsync(query),
23.         "web_search",
24.         "Searches the web for the given query and returns a list of result snippets with titles and URLs."),
25. 
26.     AIFunctionFactory.Create(
27.         ([Description("A concise heading for this note")] string title,
28.          [Description("The note content to save")] string content) =>
29.         {
30.             notebook.AddNote(title, content);
31.             return $"Note saved: \"{title}\"";
32.         },
33.         "save_note",
34.         "Saves a research note to the notebook for later use in the summary."),
35. 
36.     AIFunctionFactory.Create(
37.         () => notebook.GetAllNotes(),
38.         "get_notes",
39.         "Retrieves all previously saved research notes."),
40. };
41. 
42. // --- Agent setup -------------------------------------------------------------
43. 
44. IChatClient chatClient = new ChatClientBuilder(
45.         new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
46.     .UseFunctionInvocation()
47.     .Build();
48. 
49. var agent = new ChatClientAgent(
50.     chatClient,
51.     new ChatClientAgentOptions
52.     {
53.         Name = "ResearchAgent",
54.         Description = "An AI research agent that searches the web and summarizes findings.",
55.         ChatOptions = new ChatOptions
56.         {
57.             Temperature = 0f,
58.             MaxOutputTokens = 2048,
59.             Tools = [.. tools],
60.         },
61.     });
62. 
63. // --- Run ---------------------------------------------------------------------
64. 
65. Console.WriteLine("Research Agent");
66. Console.WriteLine(new string('=', 60));
67. Console.Write("Enter a research topic: ");
68. var topic = Console.ReadLine()?.Trim();
69. 
70. if (string.IsNullOrWhiteSpace(topic))
71. {
72.     Console.Error.WriteLine("No topic provided. Exiting.");
73.     return 1;
74. }
75. 
76. Console.WriteLine($"\nResearching: {topic}\n");
77. 
78. var instructions = $"""
79.     You are a research agent. Your goal is to thoroughly research the following topic
80.     and produce a well-structured summary.
81. 
82.     Topic: {topic}
83. 
84.     Follow these steps:
85.     1. Use the web_search tool to find relevant information. Perform 2-3 searches
86.        with different, complementary queries to get broad coverage.
87.     2. For each useful finding, use save_note to record the key facts with a
88.        descriptive title.
89.     3. Once you have gathered enough information, use get_notes to review everything,
90.        then produce a final summary.
91. 
92.     Your final response must be a structured summary with:
93.     - A brief overview
94.     - Key findings (bullet points)
95.     - Sources referenced
96.     """;
97. 
98. var messages = new List<ChatMessage>
99. {
100.     new(ChatRole.User, instructions),
101. };
102. 
103. var session = await agent.CreateSessionAsync();
104. var response = await agent.RunAsync(messages, session);
105. 
106. Console.WriteLine("=== Research Summary ===\n");
107. Console.WriteLine(response.Text ?? "(No response generated)");
108. Console.WriteLine();
109. 
110. if (notebook.Notes.Count > 0)
