127.         Notes.Add((title, content));
128. 
129.     public string GetAllNotes() =>
130.         Notes.Count == 0
131.             ? "No notes saved yet."
132.             : string.Join("\n\n", Notes.Select((n, i) =>
133.                 $"[{i + 1}] {n.Title}\n{n.Content}"));
134. }
