136. /// <summary>Web search tool using DuckDuckGo Instant Answer API (no key required).</summary>
137. static class WebSearchTool
138. {
139.     private static readonly HttpClient s_http = new()
140.     {
141.         DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
142.         Timeout = TimeSpan.FromSeconds(15),
143.     };
144. 
145.     public static async Task<string> SearchAsync(string query)
146.     {
147.         try
148.         {
149.             var encoded = Uri.EscapeDataString(query);
150.             var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
151.             var json = await s_http.GetFromJsonAsync<JsonElement>(url);
152. 
153.             var results = new List<string>();
154. 
155.             // Abstract / instant answer
156.             var abstractText = json.TryGetProperty("AbstractText", out var at) ? at.GetString() : null;
157.             var abstractSource = json.TryGetProperty("AbstractSource", out var asrc) ? asrc.GetString() : null;
158.             var abstractUrl = json.TryGetProperty("AbstractURL", out var au) ? au.GetString() : null;
159.             if (!string.IsNullOrWhiteSpace(abstractText))
160.             {
161.                 results.Add($"Source: {abstractSource}\nURL: {abstractUrl}\n{abstractText}");
162.             }
163. 
164.             // Related topics
165.             if (json.TryGetProperty("RelatedTopics", out var topics) && topics.ValueKind == JsonValueKind.Array)
166.             {
167.                 foreach (var topic in topics.EnumerateArray().Take(5))
168.                 {
169.                     var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
170.                     var firstUrl = topic.TryGetProperty("FirstURL", out var fu) ? fu.GetString() : null;
171.                     if (!string.IsNullOrWhiteSpace(text))
172.                     {
173.                         results.Add($"URL: {firstUrl}\n{text}");
174.                     }
175.                 }
176.             }
177. 
178.             return results.Count > 0
179.                 ? string.Join("\n---\n", results)
180.                 : $"No detailed results found for \"{query}\". Try a different search query.";
181.         }
182.         catch (Exception ex)
183.         {
184.             return $"Search failed: {ex.Message}. Try a different query.";
185.         }
186.     }
187. }
