         ChatOptions = new ChatOptions
         {
             Temperature = 0f,
             MaxOutputTokens = 2048,
             Tools = [.. tools],
         },
     });

 // --- Run ---------------------------------------------------------------------

 Console.WriteLine("Research Agent");
 Console.WriteLine(new string('=', 60));
 Console.Write("Enter a research topic: ");
 var topic = Console.ReadLine()?.Trim();

 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.Error.WriteLine("No topic provided. Exiting.");
     return 1;
 }

 Console.WriteLine($"\nResearching: {topic}\n");

 var instructions = $"""
     You are a research agent. Your goal is to thoroughly research the following topic
     and produce a well-structured summary.

     Topic: {topic}

     Follow these steps:
     1. Use the web_search tool to find relevant information. Perform 2-3 searches
        with different, complementary queries to get broad coverage.
     2. For each useful finding, use save_note to record the key facts with a
        descriptive title.
     3. Once you have gathered enough information, use get_notes to review everything,
        then produce a final summary.

     Your final response must be a structured summary with:
     - A brief overview
     - Key findings (bullet points)
     - Sources referenced
     """;

 var messages = new List<ChatMessage>
 {
     new(ChatRole.User, instructions),
 };

 var session = await agent.CreateSessionAsync();
 var response = await agent.RunAsync(messages, session);

 Console.WriteLine("=== Research Summary ===\n");
 Console.WriteLine(response.Text ?? "(No response generated)");
 Console.WriteLine();

 if (notebook.Notes.Count > 0)
 {
     Console.WriteLine($"--- {notebook.Notes.Count} note(s) saved during research ---");
 }

 return 0;

