 /// <summary>Simple in-memory notebook for the agent to store research notes.</summary>
 sealed class ResearchNotebook
 {
     public List<(string Title, string Content)> Notes { get; } = [];

     public void AddNote(string title, string content) =>
         Notes.Add((title, content));

     public string GetAllNotes() =>
         Notes.Count == 0
             ? "No notes saved yet."
             : string.Join("\n\n", Notes.Select((n, i) =>
                 $"[{i + 1}] {n.Title}\n{n.Content}"));
 }

 /// <summary>Web search tool using DuckDuckGo Instant Answer API (no key required).</summary>
 static class WebSearchTool
 {
     private static readonly HttpClient s_http = new()
     {
         DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
         Timeout = TimeSpan.FromSeconds(15),
     };

     public static async Task<string> SearchAsync(string query)
     {
         try
         {
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
             var json = await s_http.GetFromJsonAsync<JsonElement>(url);

             var results = new List<string>();

             // Abstract / instant answer
             var abstractText = json.TryGetProperty("AbstractText", out var at) ? at.GetString() : null;
             var abstractSource = json.TryGetProperty("AbstractSource", out var asrc) ? asrc.GetString() : null;
             var abstractUrl = json.TryGetProperty("AbstractURL", out var au) ? au.GetString() : null;
             if (!string.IsNullOrWhiteSpace(abstractText))
             {
                 results.Add($"Source: {abstractSource}\nURL: {abstractUrl}\n{abstractText}");
             }

             // Related topics
             if (json.TryGetProperty("RelatedTopics", out var topics) && topics.ValueKind == JsonValueKind.Array)
             {
                 foreach (var topic in topics.EnumerateArray().Take(5))
                 {
                     var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                     var firstUrl = topic.TryGetProperty("FirstURL", out var fu) ? fu.GetString() : null;
                     if (!string.IsNullOrWhiteSpace(text))
                     {
                         results.Add($"URL: {firstUrl}\n{text}");
                     }
                 }
             }

             return results.Count > 0
                 ? string.Join("\n---\n", results)
                 : $"No detailed results found for \"{query}\". Try a different search query.";
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }
 }
